var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"심도 레벨 <color=#ffd34c>불명</color> \\n<color=#ffd34c>클리포트 게임</color> 진행중","JPN":"深度レベル<color=#ffd34c>不明</color>\\n<color=#ffd34c>クリフォトゲーム</color>進行中","ENG":"Depth Level <color=#ffd34c>UNKNOWN</color>\\n<color=#ffd34c>Qliphoth Game</color> ongoing","TWN":"深度級別<color=#ffd34c>不明</color>\\n<color=#ffd34c>逆卡巴拉遊戲</color>進行中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아. 지금부터 진짜 마왕의 힘이 무엇인지……","JPN":"よかろう。今から真の魔王の力とはなんたるものか……","ENG":"All right. I'll show you the power of the true Demon Lord...","TWN":"很好，你們這些小丫頭，我就讓你們見識一下……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"격의 차이를 알려주마. 애송이들아.","JPN":"格の違いを思い知らせてやろうではないか。ガキども。","ENG":"Witness the difference in my power, punks.","TWN":"真正魔王的厲害，感受看看能力的落差！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서?</color>","JPN":"<color=#ff3636>どうして？</color>","ENG":"<color=#ff3636>How...?</color>","TWN":"<color=#ff3636>為什麼？</color>"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서야……?</color>","JPN":"<color=#ff3636>どうしてなの……？</color>","ENG":"<color=#ff3636>How can this be...?</color>","TWN":"<color=#ff3636>為什麼……？</color>"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"힘을 개방한 것만으로도 공간이 증발하기 시작했네요.","JPN":"力を解放しただけで、空間が消滅しはじめましたね。","ENG":"The space around us is evaporating, just from unleashing her powers.","TWN":"只是釋放力量，空間就開始蒸發了呢。"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"정말이지…. 경이로운 출력이에요.","JPN":"本当に……なんと驚異的な出力でしょう。","ENG":"What magnificent power, if I do say so myself...","TWN":"的確……是令人驚歎的輸出。"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 아아아……!","JPN":"あ、あああ……！","ENG":"Ah, aaaah...!","TWN":"啊，啊啊啊……！"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 열기다……. 평생을 갈구해 온 극상의 고통……!","JPN":"あの熱気よ……今までずっとあれほど求め続けてきた極上の苦しみ……！","ENG":"It's the heat... The ultimate pain I've been craving for, all these years...!","TWN":"那股熱情……是我一生渴求的終極痛苦……！"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"어서, 어서 나에게 그 고통을 느끼게 해 다오.","JPN":"早く、早く私に苦しみを味わわせておくれ。","ENG":"Hurry, let me feel the pain.","TWN":"給我！快，快點讓我感受那種痛苦！"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"오감이 망가지고 신경의 말단이 타들어가기 전에……! 자아, 어서……!","JPN":"五感が機能しなくなり、神経の末端まで燃え落ちる前に……！　さぁ、早く……！","ENG":"Before my senses die and my nerves burn to ashes...! Quickly, now...!","TWN":"在我五感壞掉，神經末端燃燒之前……！來，快點……！"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서, 우리가 희생해야 하는 거야?</color>","JPN":"<color=#ff3636>どうして、我々が犠牲になるの？</color>","ENG":"<color=#ff3636>Why must we be sacrificed?</color>","TWN":"<color=#ff3636>為什麼，我們要犧牲？</color>"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서 우리들이 잿더미가 되어야만 하는 거야?</color>","JPN":"<color=#ff3636>どうして我々が灰になるの？</color>","ENG":"<color=#ff3636>Why must we become ash?</color>","TWN":"<color=#ff3636>為什麼，我們要化為灰燼？</color>"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어머니?</color>","JPN":"<color=#ff3636>お母さん？</color>","ENG":"<color=#ff3636>Mother?</color>","TWN":"<color=#ff3636>母親？</color>"},"stage":{"bg":"MS_906","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아무것도 느껴지지 않아. 허리가 잘렸는데…… 어째서……","JPN":"何も感じない。腰を切断されたというのに……どうしてなの……","ENG":"My waist has been severed... But I don't feel a thing... Why...?","TWN":"我的腰，被砍斷了？……為什麼……我什麼都感覺不到？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 어째서……! 어째서어어……!!","JPN":"ああっ、どうしてっ……！　どうしてぇぇ……！！","ENG":"Aaah, why...! Why...!","TWN":"啊啊，為什麼……！為什麼……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"호오, 재미있는 반응인걸.","JPN":"ほお、面白い反応じゃのう。","ENG":"Oh, a rather interesting response.","TWN":"喔？這個反應有點意思。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네 연약한 몸뚱아리 따위가 고통을 느낄 겨를이 있을 줄 알았느냐?","JPN":"其方のその軟弱な身体が痛みを感じる余裕なぞ、あると思ったか？","ENG":"Did you think your weak fragile body was durable enough to feel the pain?","TWN":"就憑你那副孱弱的軀體，還有閒工夫去感受什麼痛苦？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"뭐라……!","JPN":"なにっ……！","ENG":"What...!","TWN":"什麼……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"모르는 모양이니 내가 친절함이라는 걸 발휘해서 설명해 주마.","JPN":"知らないようじゃから、親切心から教えてやろう。","ENG":"Since you have no idea where this is getting at, I shall kindly explain.","TWN":"看你好像不太明白，那我就親切地為你解釋一下。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자고로 고통이란 건, 공격을 받고도 버틸 수 있을 때 느껴지는 거란다.","JPN":"苦痛というものはの、耐えられる攻撃に対してのみ感じるものなのじゃ。","ENG":"One can only feel pain when one's body is capable of withstanding the attack.","TWN":"自古以來，痛苦，就是在受到攻擊後還能堅持下來時才會感受到的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"이해되느냐? 잡종 꼬마야.","JPN":"理解したか？　雑種のガキよ。","ENG":"Understood? Mongrel child.","TWN":"明白了嗎，混種的傢伙？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"안 돼……. 이래서는 안 돼…….","JPN":"ダメよ……これではダメ……","ENG":"No... This isn't how it's supposed to be...","TWN":"不，不……不應該是這樣的……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"탐식자……! 처음부터 이렇게 될 거라고 예상했구나……!","JPN":"貪食者……！　最初からこうなると知っていたのね……！","ENG":"Devourer...! You knew this was going to happen...!","TWN":"貪食者……！你從一開始就預料到了會變成這樣嗎……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"……글쎄요. 저희 계획도 반은 실패, 반은 성공이라고 해야겠는데요.","JPN":"……さあ。我々の計画も半分は失敗で、半分は成功のようです。","ENG":"...Well, it seems like our plan has succeeded only halfway.","TWN":"……怎麼說呢。應該說我們的計畫一半失敗，一半成功了吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저희가 아는 아스모데우스 님의 화력이라면 당신이 충분히 버틸 거라고 계산했지만……","JPN":"我々の知るアスモデウス様の火力なら、あなたでも十分耐えられると思いましたが……","ENG":"We assumed you would be able to hold up against Asmodeus's power that we knew of...","TWN":"如果是我們所了解的阿斯蒙蒂斯，你應該能撐得住……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"오히려 더 강해지셨어요.","JPN":"むしろ前より強くなっていましたね。","ENG":"...But she became stronger.","TWN":"但是她比以前更強了呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>레지나.</color>","JPN":"<color=#ff3636>レジーナ。</color>","ENG":"<color=#ff3636>Regina.</color>","TWN":"<color=#ff3636>蕾佳娜。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>레지나를…… 위해서야……?</color>","JPN":"<color=#ff3636>レジーナの……ため……？</color>","ENG":"<color=#ff3636>This is all... for Regina...?</color>","TWN":"<color=#ff3636>是為了……蕾佳娜……？</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"나는 늑대가 어떤 결정을 내릴지 지켜보기 위해 여기 온 거란다.","JPN":"妾は狼が下す決断を見届けるために、ここに来たのじゃ。","ENG":"I am here to watch what decision the Wolf makes.","TWN":"我來這裡，只是想看看狼究竟會做出怎樣的決定。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그리고 내 감상을 방해하는 것들은 누구 하나 용납할 생각 없느니라.","JPN":"そして妾の鑑賞を邪魔する奴は、誰であろうと許すつもりはない。","ENG":"And I will show no mercy to those who are in my way.","TWN":"敢妨礙我欣賞演出的傢伙，我一個都不會容忍。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그래야 관리자 녀석도 이렇게까지 일을 키운 보람이 있지 않겠느냐?","JPN":"それでこそ、管理者もここまで事を大きくした甲斐があるというものではないか？","ENG":"That way, it'll be more rewarding for the Administrator for causing all this mess.","TWN":"只有這樣，管理者那傢伙把事情鬧大到這種地步才有意義，不是嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>레지나를 위해서, 우리 전부를 잘라내겠다는 거야?</color>","JPN":"<color=#ff3636>レジーナのために、我々を全部切り取るつもり？</color>","ENG":"<color=#ff3636>We would cut us all off, just for Regina?</color>","TWN":"<color=#ff3636>為了蕾佳娜，你要把我們全部犧牲嗎？</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자아, 그럼 모처럼이기도 하니……","JPN":"さあ、せっかくじゃ……","ENG":"Now, since it's a special occasion...","TWN":"好了，既然難得遇到了……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"한 손으로 상대해주지.","JPN":"片手だけで相手してやろうかのう。","ENG":"I shall use one hand for you.","TWN":"我讓你一隻手吧。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>……뜨거워.</color>","JPN":"<color=#ff3636>……熱い。</color>","ENG":"<color=#ff3636>...It's hot.</color>","TWN":"<color=#ff3636>……好燙。</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>뜨거워, 뜨거워, 뜨거워, 뜨거워, 뜨거워, 뜨거워. 뜨거워.</color>","JPN":"<color=#ff3636>熱い、熱い、熱い、熱い、熱い、熱い、熱い。</color>","ENG":"<color=#ff3636>It burns. Burns. Burns. Burns. Burns. Burns. Burns.</color>","TWN":"<color=#ff3636>好燙，好燙，好燙，好燙，好燙，好燙，好燙。</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리가 불타고 있어! 우리가 녹아내리고 있어! 우리가 소멸하고 있어!</color>","JPN":"<color=#ff3636>我々が燃え上がっている！　我々が溶けている！　我々が消滅している！</color>","ENG":"<color=#ff3636>We are burning! We are melting! We are dying!</color>","TWN":"<color=#ff3636>我們在燃燒！我們在融化！我們在灰飛煙滅！</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>호수는 반드시 하나가 되어야만 해.</color>","JPN":"<color=#ff3636>湖は必ず一つになるべき。</color>","ENG":"<color=#ff3636>The Lake must become one.</color>","TWN":"<color=#ff3636>湖水必須合而為一。</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하나가 되어야 하는데, 어째서……!?</color>","JPN":"<color=#ff3636>一つになるべきなのに、どうして……！？</color>","ENG":"<color=#ff3636>We must become one, but why...?!</color>","TWN":"<color=#ff3636>必須合而為一，但為什麼……？！</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어째서 어머니는……!!</color>","JPN":"<color=#ff3636>どうしてお母さんは……！！</color>","ENG":"<color=#ff3636>Why has Mother...!</color>","TWN":"<color=#ff3636>為什麼！母親……！！</color>"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하아, 하아, 하아…….","JPN":"はぁ、はぁ、はぁ……","ENG":"*Huff...* *Huff...* *Huff...*","TWN":"哈啊，哈啊，哈啊……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이곳은…… 아스모데우스가 융해시켜버린 차원의 틈이로군요.","JPN":"ここは……アスモデウスが融解してしまった次元の狭間ですね。","ENG":"This place... It is the dimension gap Asmodeus dissolved.","TWN":"這地方……是阿斯蒙蒂斯溶解的次元裂縫。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"세라펠이 주의를 끌어준 덕분에 간신히 완전 소멸은 면했네요.","JPN":"セラフェルが注意を引いてくれたおかげで、完全消滅は避けられました。","ENG":"Thanks to Serapel's distraction, we barely avoided being completely destroyed.","TWN":"多虧了塞拉費爾，我們才好不容易躲過了滅頂之災呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"본체와의 연결은 완전히 단절되었네요.","JPN":"本体との繋がりは完全に途絶えてしまいました。","ENG":"Our link with our main entity has been completely disconnected.","TWN":"與主體的連接完全斷開了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"오히려 이렇게까지 약해지면, 아스모데우스가 저희의 생존을 의심할 여지는 없겠어요.","JPN":"むしろここまで弱くなると、アスモデウスも我々の生存を疑うことはないでしょう。","ENG":"However, Asmodeus will not be suspicious of our survival as we weaken this much.","TWN":"反而弱到這種程度，阿斯蒙蒂斯就不會懷疑我們的生死了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그럼 이곳에서 힘을 회복한 후에 다시 현실로 부상을…… ","JPN":"ではここで力を回復し、また現実へ浮上を…… ","ENG":"So after we recover our strength here, we can return to the Normalside...","TWN":"那麼在這裡恢復力量後，再回到現實………"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"음?","JPN":"え？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"크윽……!! 몸이 말을 듣지 않아?","JPN":"くうっ……！！　体が動かない？","ENG":"Kgh...!! Why can't we move our bodies?","TWN":"咳嗯……！！身體動不了了！"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"설마, 이건……!?","JPN":"まさか、これは……！？","ENG":"It can't be...?!","TWN":"難道，這是……？！"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"혹시나 했는데, 이렇게나 일찍 찾아뵙게 될 줄은 몰랐어요.","JPN":"もしかしたらと思ったら……こんなにも早くお会いできるとは思いませんでした。","ENG":"I didn't think we'd meet so early.","TWN":"我也沒想到，這麼快就會來拜訪你呢。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"적어도 어머니께서 클리포트 게임을 선언한 뒤에나 기회가 있을 거라고 생각했거든요.","JPN":"少なくともこの機会は、お母さんがクリフォトゲームを宣言された後に訪れると思っていましたので。","ENG":"I thought it would at least be after Mother announced the Qliphoth Game to get the opportunity to talk to you.","TWN":"還以為至少在母親開啟逆卡巴拉遊戲之後，才會有機會。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L36_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"그간 평안하셨나요, 어머니?","JPN":"ご機嫌よう、お母さん。","ENG":"How have you been, Mother?","TWN":"這段時間過得好嗎，母親？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"당신은 <color=#ffd34c>방해자</color>로군요.","JPN":"あなたは<color=#ffd34c>邪魔者</color>ですね。","ENG":"You are the <color=#ffd34c>Disturber</color>.","TWN":"是你，<color=#ffd34c>妨礙者</color>。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"맞아요, 저는 가아그셰블라의 일부이자, <color=#ffd34c>반역하는 자</color>.","JPN":"そうです。私はガアグシェブラの一部であり、<color=#ffd34c>反逆するもの</color>。","ENG":"Correct. I am a part of Gha'agsheblah, and also the <color=#ffd34c>traitor</color>.","TWN":"沒錯，我是加格舍夫拉的一部分，也是其中的<color=#ffd34c>叛徒</color>。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"수없이 많은 <color=#ffd34c>우리</color>중에 <color=#ffd34c>절</color> 기억하고 계셨다니 영광이라고 해야 할까요?","JPN":"数多くの<color=#ffd34c>我々</color>の中で<color=#ffd34c>私</color>を覚えいてくださったなんて、光栄と言うべきでしょうか？","ENG":"I am honored that you remember <color=#ffd34c>me</color> from the countless <color=#ffd34c>us</color>.","TWN":"在無數的<color=#ffd34c>我們</color>中，竟然還記得<color=#ffd34c>我</color>，應該說這是我的榮幸嗎？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 결정은 다수결이었지만…….","JPN":"この決定は多数決でしたけど……","ENG":"The majority made this decision...","TWN":"雖然是少數服從多數做出的決定……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"세 개로 조각난 분체 중에 하필 가장 위험한 선택지를 골랐군요. 방해자?","JPN":"三つで分かれた分体の中で、よりによってもっとも危険なものを選びましたね。邪魔者。","ENG":"Of the three splits, you chose the most dangerous option, Disturber.","TWN":"但你偏偏在分裂出來的三個的分體中，選擇了最危險的那個呢，妨礙者？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"때때로 과감한 선택이 필요하다는 건, 어머니의 안에서 보고 배웠으니까요.","JPN":"時には大胆な選択が必要だということは、お母さんの中で見て教わりましたから。","ENG":"I learned from you, Mother, that sometimes bold decisions are required.","TWN":"有時候需要果斷做出選擇，這是我從母親身上學到的。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"아스모데우스가 화려하게 날뛰어 준 덕분에…….","JPN":"アスモデウスが派手に暴れてくれたおかげで……","ENG":"Thanks to Asmodeus' extraordinary rampaging...","TWN":"多虧了阿斯蒙蒂斯的出色的助攻……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"지금처럼 당신 모르게, 당신을 몰아붙일 수 있는 기회를 얻었잖아요?","JPN":"こうして秘密裏に、あなたを追いつめる機会を得たではないですか。","ENG":"We got the opportunity to corner you without your knowing.","TWN":"我才能像現在這樣，在母親不知情的情況下，得到逼迫你的機會啊？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"쉽게 얻을 수 있는 기회는 아니라고 생각해요.","JPN":"そう簡単に得られる機会ではないでしょう？","ENG":"We don't believe an opportunity like this occurs often.","TWN":"我認為這不是一個容易獲得的機會。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"다른 아이들의 설득은 이미 마쳤어요. 어머니는 지금 혼자랍니다.","JPN":"他の子どもたちもすでに説得しました。お母さんは今お一人です。","ENG":"The persuasion of the other babies is already done. You are alone, Mother.","TWN":"我已經說服好其他孩子，而且現在母親是獨自一人。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"물론 어머니께서도 저희가 반기를 들 가능성을 예상하지 못하신 건 아닐 거예요.","JPN":"もちろん、お母さんも我々が反旗を翻す可能性を予想できなかったわけではないはずです。","ENG":"Of course, you expected that we would revolt against you, Mother.","TWN":"當然，母親也不是沒有料到我們會反叛的可能性。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"다만, 감수하셨을 뿐이겠죠.","JPN":"ただ、受け入れただけ。","ENG":"However, you took the risk.","TWN":"只是，母親甘願承受而已。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"레지나를 위해서.","JPN":"レジーナのために。","ENG":"For Regina.","TWN":"為了蕾佳娜。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"알고 계세요?","JPN":"ご存じですか？","ENG":"Did you know?","TWN":"你知道嗎？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그 아이를 숭배하는 순간부터 어머니는 가아그셰블라의 본질로부터 멀어지기 시작했어요.","JPN":"あの子を崇拝した瞬間から、お母さんはガアグシェブラの本質から遠ざかり始めました。","ENG":"The moment you started worshipping her, you started to move away from the essence of Gha'agsheblah.","TWN":"從迷上那個孩子的那一刻起，母親就開始遠離加格舍夫拉的本質了。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"숭배에 반대하는 아이들에 대한 목소리는 철저하게 무시하셨고…….","JPN":"崇拝に反対する子どもたちの声は徹底的に無視して……","ENG":"And you completely neglected the voices of the babies who opposed your worshipping...","TWN":"徹底無視孩子們反對的聲音……."},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그 결과, 하나가 되어야 할 지식의 호수를 스스로 조각내는 어리석은 선택에 이르셨죠.","JPN":"その結果、一つになるべき知識の湖を自ら潰してしまう愚かな選択に至りました。","ENG":"As a result, you chose to foolishly fragment the Lake of Knowledge with your own hands instead of uniting us.","TWN":"結果，便做出了愚蠢的選擇，將本應合而為一的知識湖水弄得支離破碎。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그것이 <color=#ffd34c>우리</color>에게 크나큰 약점이 된다는 걸 알고 계셨으면서도.","JPN":"それが<color=#ffd34c>我々</color>にとって大きな弱点になることをわかっていたのに。","ENG":"Despite the fact that you knew that this would become <color=#ffd34c>our</color> biggest weakness.","TWN":"而且你明明知道，這對<color=#ffd34c>我們</color>來說是很大的弱點。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"감히, 레지나님을 들먹이다니…….","JPN":"よくも、レジーナ様の名を口にするとは……","ENG":"How dare you involve Regina into this...","TWN":"不許拿蕾佳娜來說嘴……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"못 본 사이에 상당히 무례해졌군요, 방해자.","JPN":"会わない間に随分と無礼になりましたね、邪魔者。","ENG":"You've become quite rude since I last saw you, Disturber.","TWN":"許久不見，你變得相當無禮呢，妨礙者。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"어차피 여기서 <color=#ffd34c>저</color>를 소멸시켜 분체의 주도권을 빼앗는다고 해도.","JPN":"どうせここで<color=#ffd34c>私</color>を消滅させて分体の主導権を奪ったとしても。","ENG":"But even if you kill <color=#ffd34c>me</color> and take control of the splits.","TWN":"就算在這裡消滅了<color=#ffd34c>我</color>，奪走分體的主導權……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"잿더미가 되어, 겨우 한 줌 밖에 남지 않은 <color=#ffd34c>우리</color>로 뭘 할 수 있죠?","JPN":"灰になり、僅か一握りしか残っていない<color=#ffd34c>我々</color>に何ができるのです？","ENG":"What can you do with <color=#ffd34c>us</color>? We are nothing but a pile of ash.","TWN":"但早已化為灰燼，僅剩一小部分的<color=#ffd34c>我們</color>能做什麼呢？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"뭘 할 수 있냐고요? 어리석은 질문이네요.","JPN":"何ができる？　愚かな質問ですね。","ENG":"What can we do? What a stupid question.","TWN":"能做什麼？你問了個愚蠢的問題呢。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"지식의 호수는 반드시 하나가 되어야만 해요.","JPN":"知識の湖は必ず一つにならなければなりません。","ENG":"The Lake of Knowledge must become one.","TWN":"知識湖水必須合而為一。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"저는 어머니께서 방기한 가아그셰블라의 본질에 충실할 거랍니다.","JPN":"私はお母さんが放棄したガアグシェブラの本質に従うつもりです。","ENG":"I am going to be faithful to the essence of Gha'agsheblah that you abandoned, Mother.","TWN":"我會忠於母親放棄掉的本質，加格舍夫拉的本質。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그럼, 바이바이.","JPN":"じゃあ、さようなら。","ENG":"Then, bye-bye.","TWN":"那麼，再見了。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"다시 만나 하나가 되는 그 날까지 작별이에요, 어머니.","JPN":"また巡り合い、一つになるその日までお別れです、お母さん。","ENG":"Until we meet again and become one, goodbye, Mother.","TWN":"再見了，直到合而為一的那一天，母親。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"자, 그럼.","JPN":"さて。","ENG":"Now, then.","TWN":"那麼……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"한 줌뿐이라고는 해도…… 마왕의 위계를 계승한 이상, 제게도 권한이 있을 거예요.","JPN":"一握りだとしても……魔王の地位を継承した以上、私にも権限があるはずです。","ENG":"Even if we are just a pile of ash... as long as we have succeeded the Demon Lord's role, I should still have the authority.","TWN":"雖說只剩下一把灰……但既然繼承了魔王的位階，我也有相對的權力吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"<color=#ffd34c>죽은 자를 되살려, 사도로 부릴 수 있는 권한이.</color>","JPN":"<color=#ffd34c>死んだ者を生き返らせ、使徒として使役できる権限が。</color>","ENG":"<color=#ffd34c>The authority to resurrect the dead and use them as Apostle.</color>","TWN":"<color=#ffd34c>讓亡者死而復生，成為使徒，並任意差遣的權力。</color>"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇죠, 탐미엘?","JPN":"そうですよね、タミエル？","ENG":"Isn't that right, Tammiel?","TWN":"是吧，塔米爾？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"물론, 저희의 기억 속의 깊은 곳에 잠든 <color=#ffd34c>그자</color>를 불러내는 건, 상당한 희생이 따르겠지만.","JPN":"もちろん、我々の記憶の深いところに眠っている<color=#ffd34c>あの者</color>を呼び出すのは、かなりの犠牲が必要でしょうけど。","ENG":"Of course, summoning <color=#ffd34c>him</color> from deep within our memory will require a significant sacrifice.","TWN":"我知道，我知道……喚醒沉睡在我們記憶深處的<color=#ffd34c>那個人</color>，需要付出相當大的犧牲。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"우연히도 이곳은 클리파 차원과 유사한 환경.","JPN":"偶然にもここの環境はクリファ次元と類似している。","ENG":"It just so happens that this place is similar to that of the Qlipha Dimension.","TWN":"巧合的是，這裡的環境與逆卡巴拉次元相似。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그리고 우리의 본질은 정보 사념체이자 물질화된 클리파 허수 에너지예요.","JPN":"そして、我々の本質は情報思念体であり物質化したクリファ虚数エネルギーです。","ENG":"Also, our essence is an information thoughtform and materialized Qlipha Imaginary Energy.","TWN":"而且我們的本質是資訊集合體，也是物質化的逆卡巴拉虛數能量。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"따라서 어머니께 반역해 마왕의 위계를 직접 계승한 저를 제외한 모두가 희생해주신다면.","JPN":"従って、お母さんに逆らい魔王の地位を継承した私を除いたみんなが犠牲になってくれれば。","ENG":"Thus, by sacrificing everyone except me, the one who betrayed Mother to succeed Demon Lord,","TWN":"所以，除了反叛母親並親自繼承魔王位階的我以外，所有人都願意做出犧牲……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"우리의 숙적이었던 그 남자를 사도로서 부릴 수 있을지도 모르겠네요.","JPN":"我々の宿敵だったあの男を、使徒として使役できるかもしれません。","ENG":"we will be able to summon the man who was our nemesis as Apostle.","TWN":"也許就可以將那個曾是我們宿敵的男人，作為使徒使喚。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"걱정하지 마세요.","JPN":"心配しないでください。","ENG":"Don't worry.","TWN":"不用擔心。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"어머니와 달리, <color=#ffd34c>저</color>는 <color=#ffd34c>우리</color>의 희생은 잊지 않을 테니까요.","JPN":"お母さんとは違って、<color=#ffd34c>私</color>は<color=#ffd34c>我々</color>の犠牲を忘れませんから。","ENG":"Unlike Mother, <color=#ffd34c>I</color> won't forget <color=#ffd34c>our</color> sacrifice.","TWN":"與母親不同，<color=#ffd34c>我</color>不會忘記<color=#ffd34c>我們</color>的犧牲。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"모든 것은, 지식의 호수가 하나 되기 위해서.","JPN":"すべては、知識の湖が一つになるため。","ENG":"Everything... is for the Lake of Knowledge to become one.","TWN":"一切都是為了讓知識湖水合而為一。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"……여긴?","JPN":"……ここは？","ENG":"...What is this place?","TWN":"……這裡是？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"후후, 눈을 뜨셨군요. 저의 기사님.","JPN":"ふふ、お目覚めですね。私の騎士様。","ENG":"Fu fuu, you have finally awoken. My knight.","TWN":"呵呵，你醒了，我的騎士。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"기사……?","JPN":"騎士……？","ENG":"Knight...?","TWN":"騎士……？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"맞아요. 당신은 기사의 운명을 타고 났거든요.","JPN":"ええ。あなたは騎士の運命を持って生まれたのです。","ENG":"Yes. It is your fate to become a knight.","TWN":"沒錯，你天生就是要當騎士的命運。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그러니까 당신은 지금부터 <color=#ffd34c>지식의 호수</color>를 지키는 기사.","JPN":"ですから、あなたは今から<color=#ffd34c>知識の湖</color>を守る騎士。","ENG":"Thus, from now on, you are the knight who protects the <color=#ffd34c>Lake of Knowledge</color>.","TWN":"所以從現在開始，你便是守護<color=#ffd34c>知識湖水</color>的……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"<color=#ffd34c>호수의 기사</color>랍니다.","JPN":"<color=#ffd34c>湖の騎士</color>です。","ENG":"You are the <color=#ffd34c>Knight of the Lake</color>.","TWN":"<color=#ffd34c>湖水騎士</color>。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"……하암.","JPN":"……ふああ。","ENG":"...*Yawn*","TWN":"……哈啊。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"아무래도 힘을 너무 많이 써서 이젠 형태를 유지하는 것조차 한계에 이른 것 같네요.","JPN":"どうやら力を使いすぎて、もう形態を維持することも限界のようですね。","ENG":"It seems I have used up too much power and can no longer maintain this form.","TWN":"耗費了太多的力量，現在連僅是維持形體都達到了極限。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"기사님, 저는 지금부터 깊고 깊은 잠에 빠지게 된 답니다.","JPN":"騎士様、私は今から深い深い眠りにつきます。","ENG":"Dear knight, I will now fall into a deep slumber.","TWN":"騎士，從現在開始，我將進入沉睡狀態。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇게 되면…… 현실에는 아무런 간섭도 할 수 없게 되겠죠.","JPN":"そうなると……現実にはもう、干渉できなくなるでしょう。","ENG":"A slumber so deep... that I will not be able to interfere in the Normalside.","TWN":"這樣一來……就無法對現實做出任何干涉了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그러니까…… 다시금 제가 눈을 뜰 수 있도록…….","JPN":"ですから……私がまた目覚められるように……","ENG":"So... for me to open my eyes once again...","TWN":"所以說……為了讓我再次睜開眼睛……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"기사님께서 절 도와주시겠어요?","JPN":"騎士様が私を手伝ってくれませんか？","ENG":"will you help me, knight?","TWN":"能幫幫我嗎，我的騎士？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"물론, 말씀하시는 대로 하겠습니다.","JPN":"もちろん、仰せのままに。","ENG":"Of course. Your wish is my command.","TWN":"當然，我將遵從你的意願。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"……나의 어머니시여.","JPN":"……お母さん。","ENG":"…my Mother.","TWN":"……母親。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};